// app.js content
// Configuration
const CLIENT_ID = 'YOUR_CLIENT_ID'; // <<< REPLACE WITH YOUR ACTUAL CLIENT ID >>>
// Example: '1234567890-abcdefghijklmnop.apps.googleusercontent.com'
const AUTHORIZATION_ENDPOINT = 'YOUR_AUTHORIZATION_ENDPOINT'; // <<< REPLACE WITH YOUR PROVIDER'S AUTH ENDPOINT >>>
// Example for Google: 'https://accounts.google.com/o/oauth2/v2/auth'
// Example for Auth0: 'https://YOUR_DOMAIN.auth0.com/authorize'

// The current page URL will be the redirect URI.
// Ensure this exact URL (e.g., http://localhost:8000) is registered with your OAuth provider.
const REDIRECT_URI = window.location.origin;

const SCOPE = 'profile email'; // Request desired scopes, e.g., 'openid profile email' for OIDC. Adjust as needed.
const RESPONSE_TYPE = 'token'; // Specifies Implicit Flow: requests access token directly.

const authStatusDiv = document.getElementById('auth-status');
const loginButton = document.getElementById('loginButton');
const logoutButton = document.getElementById('logoutButton');

/**
 * Parses the URL fragment (hash) to extract parameters like access_token.
 * @returns {Object} An object containing the fragment parameters.
 */
function parseUrlFragment() {
    const fragmentString = window.location.hash.substring(1); // Remove the '#'
    const params = {};
    if (fragmentString) {
        fragmentString.split('&').forEach(param => {
            const parts = param.split('=');
            if (parts.length === 2) {
                // Decode URI components as values might be URL-encoded
                params[decodeURIComponent(parts[0])] = decodeURIComponent(parts[1]);
            }
        });
    }
    return params;
}

/**
 * Initiates the OAuth login flow by redirecting the user to the authorization endpoint.
 */
function initiateLogin() {
    const authUrl = new URL(AUTHORIZATION_ENDPOINT);
    authUrl.searchParams.append('client_id', CLIENT_ID);
    authUrl.searchParams.append('redirect_uri', REDIRECT_URI);
    authUrl.searchParams.append('response_type', RESPONSE_TYPE);
    authUrl.searchParams.append('scope', SCOPE);
    // Optional: Add 'state' parameter for CSRF protection.
    // const state = generateRandomString(); // Implement your own state generation
    // authUrl.searchParams.append('state', state);
    // localStorage.setItem('oauth_state', state); // Store state to verify on redirect

    window.location.href = authUrl.toString();
}

/**
 * Handles the logout process by clearing any stored tokens and resetting the UI.
 * In Implicit Flow, this primarily means clearing local state and the URL fragment.
 */
function handleLogout() {
    // Clear any token data that might have been stored locally
    localStorage.removeItem('access_token');
    localStorage.removeItem('expires_in');
    // Clear the URL fragment to remove token visible in the URL bar
    window.location.hash = '';
    // Reload the page to reset the application state and re-run checkAuthStatus
    window.location.reload();
}

/**
 * Main function to check authentication status on page load and update the UI.
 */
function checkAuthStatus() {
    const fragmentParams = parseUrlFragment();
    const accessToken = fragmentParams.access_token;
    const expiresIn = fragmentParams.expires_in; // How long until token expires (in seconds)

    // Optional: Verify 'state' parameter if it was sent during login for CSRF protection.
    // const storedState = localStorage.getItem('oauth_state');
    // if (storedState && fragmentParams.state && storedState === fragmentParams.state) {
    //     localStorage.removeItem('oauth_state'); // Clear state after verification
    // } else if (fragmentParams.state) {
    //     console.error('State mismatch! Possible CSRF attack.');
    //     // Optionally, handle error or prevent further processing
    //     authStatusDiv.innerHTML = '<p style="color: red;">Authentication failed: State mismatch!</p>';
    //     loginButton.style.display = 'inline-block';
    //     logoutButton.style.display = 'none';
    //     return;
    // }

    if (accessToken) {
        // Successfully received an access token from the URL fragment
        authStatusDiv.innerHTML = `
            <p><strong>Authentication Successful!</strong></p>
            <p>Access Token: <code>${accessToken}</code></p>
            <p>Expires In: ${expiresIn ? expiresIn + ' seconds' : 'N/A'}</p>
            <p>Token obtained at: ${new Date().toLocaleString()}</p>
            <p style="font-size: 0.9em; color: #555;">Note: For security, a real application would typically clear the fragment from the URL bar immediately after parsing, storing the token in <code>sessionStorage</code>.</p>
        `;
        loginButton.style.display = 'none';
        logoutButton.style.display = 'inline-block';

        // Optionally, store the token in sessionStorage (more secure than localStorage for short-lived tokens)
        // sessionStorage.setItem('access_token', accessToken);
        // sessionStorage.setItem('expires_in', expiresIn);

        // To clear the URL fragment after parsing (keeping the URL clean and hiding token from browser history)
        // window.history.replaceState({}, document.title, window.location.pathname);
        // If you clear the fragment, ensure you've stored the token elsewhere (e.g., sessionStorage)
        // if (sessionStorage.getItem('access_token')) { ... }
    } else {
        // No access token found in the URL fragment
        authStatusDiv.innerHTML = '<p>Not authenticated.</p>';
        loginButton.style.display = 'inline-block';
        logoutButton.style.display = 'none';
    }
}

// Attach event listeners to buttons
loginButton.addEventListener('click', initiateLogin);
logoutButton.addEventListener('click', handleLogout);

// Run the authentication check when the page loads
document.addEventListener('DOMContentLoaded', checkAuthStatus);